function loadProtoFile(filePath) {
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    xhr.open('GET', filePath, true);
    xhr.onload = function() {
      if (xhr.status === 200) {
        resolve(xhr.responseText);
      } else {
        reject(new Error(`Failed to load ${filePath}: ${xhr.status}`));
      }
    };
    xhr.onerror = function() {
      reject(new Error(`Network error loading ${filePath}`));
    };
    xhr.send();
  });
}

function parseProto(content) {
  const lines = content.split('\n');
  const result = { package: '', messages: [], enums: [] };
  let currentMessage = null;
  let currentEnum = null;
  
  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.startsWith('package ')) {
      result.package = trimmed.replace('package ', '').replace(';', '').trim();
    } else if (trimmed.startsWith('message ')) {
      if (currentMessage) result.messages.push(currentMessage);
      const name = trimmed.replace('message ', '').replace('{', '').trim();
      currentMessage = { name, fields: [] };
    } else if (trimmed.startsWith('enum ')) {
      if (currentEnum) result.enums.push(currentEnum);
      const name = trimmed.replace('enum ', '').replace('{', '').trim();
      currentEnum = { name, values: [] };
    } else if (currentEnum && trimmed.includes('=')) {
      const parts = trimmed.split('=');
      const valueName = parts[0].trim();
      const valueNum = parseInt(parts[1].replace(',', '').replace(';', '').trim());
      if (!isNaN(valueNum)) {
        currentEnum.values.push({ name: valueName, value: valueNum });
      }
    } else if (currentMessage && trimmed.includes('=')) {
      const match = trimmed.match(/(\d+)\s+(\w+)\s+(\w+)\s*=\s*(\d+)/);
      if (match) {
        currentMessage.fields.push({
          id: parseInt(match[4]),
          type: match[2],
          name: match[3],
          repeated: match[1] === 'repeated'
        });
      }
    } else if (trimmed === '}' && currentMessage) {
      result.messages.push(currentMessage);
      currentMessage = null;
    } else if (trimmed === '}' && currentEnum) {
      result.enums.push(currentEnum);
      currentEnum = null;
    }
  }
  
  return result;
}